// ```
//
//	{
//	  'text': 'show me sales by product'
//	}
//
// ```
// ```
//
//	{
//	  'fields': [
//	    {
//	      'name': 'product'
//	    }
//	  ],
//	  'libItems': [
//	    {
//	      libId: 'NwQfJ'
//	    }
//	  ]
//	}
//
// ```
